const items = $input.all();

return items.map(item => ({
  json: {
    ...item.json,
    processed: true,
    timestamp: new Date().toISOString()
  }
}));

const items = $input.all();

// Filter active items
return items
  .filter(item => item.json.status === 'active')
  .map(item => ({ json: item.json }));

const items = $input.all();

const total = items.reduce((sum, item) => sum + (item.json.amount || 0), 0);
const count = items.length;
const average = count > 0 ? total / count : 0;

return {
  json: {
    total,
    count,
    average: average.toFixed(2)
  }
};

const items = $input.all();

const grouped = items.reduce((acc, item) => {
  const key = item.json.category || 'other';
  if (!acc[key]) acc[key] = [];
  acc[key].push(item.json);
  return acc;
}, {});

return Object.entries(grouped).map(([category, items]) => ({
  json: { category, items, count: items.length }
}));

const items = $input.all();

return items.map(item => {
  const errors = [];

  if (!item.json.email) errors.push('Email required');
  if (!item.json.name) errors.push('Name required');
  if (item.json.email && !item.json.email.includes('@')) {
    errors.push('Invalid email format');
  }

  return {
    json: {
      ...item.json,
      valid: errors.length === 0,
      errors: errors.length > 0 ? errors : undefined
    }
  };
});

const RTL = '\u200F';
const LTR = '\u200E';

const items = $input.all();

return items.map(item => ({
  json: {
    ...item.json,
    formatted_text: RTL + item.json.text,
    // For mixed content
    mixed_text: `${RTL}${item.json.hebrew}${LTR}${item.json.english}`
  }
}));

const response = await $helpers.httpRequest({
  method: 'GET',
  url: 'https://api.example.com/data',
  headers: {
    'Authorization': `Bearer ${$env.API_KEY}`
  }
});

return {
  json: response
};
